const staticData = $getWorkflowStaticData('global');
const raw = $input.first().json;

// Calls are at top level, cursor is inside records
const currentCalls = raw.calls || [];
const cursor = raw.records?.cursor || null;

if (!staticData.gongCalls) {
  staticData.gongCalls = [];
}
staticData.gongCalls.push(...currentCalls);

return [{
  json: {
    cursor: cursor,
    pageSize: currentCalls.length,
    runningTotal: staticData.gongCalls.length,
    pageNumber: Math.ceil(staticData.gongCalls.length / 100)
  }
}];

const staticData = $getWorkflowStaticData('global');
const allCalls = staticData.gongCalls || [];

// Clear for next workflow run
delete staticData.gongCalls;

return [{
  json: {
    calls: allCalls,
    totalCount: allCalls.length
  }
}];

const accountName = $('Salesforce - Get Opportunity')
  .first().json.Account?.Name 
  || $('Salesforce - Get Opportunity').first().json.Name 
  || '';

// Strips common suffixes and noise from names for fuzzy matching.
// ✏️ ADD your own product names, partner names, and internal labels
// to the second .replace() line below so they don't interfere with matching.
const stripSuffixes = (name) => {
  return name
    .toLowerCase()
    .replace(/[.,\-()\/<>]/g, ' ')
    // Business suffixes — keep these
    .replace(/\b(inc|incorporated|corp|corporation|llc|ltd|limited|co|company|group|holdings|enterprises|international|intl|the)\b/g, '')
    // ✏️ YOUR PRODUCT / BRAND TERMS — add terms that appear in call titles
    // but shouldn't be used for account matching
    .replace(/\b(implementation|pilot|poc|renewal|expansion|upsell|demo|kickoff|review|follow up)\b/g, '')
    .replace(/\s*[\-|><\/]+\s*/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
};

const cleanName = stripSuffixes(accountName);
const nameTokens = cleanName.split(' ').filter(w => w.length > 1);

const allCalls = $input.first().json.calls || [];

const scored = allCalls.map(call => {
  const cleanTitle = stripSuffixes(call.title || '');
  const titleTokens = cleanTitle.split(' ').filter(w => w.length > 1);
  const hits = nameTokens.filter(token => 
    titleTokens.some(t => t.includes(token) || token.includes(t))
  );
  const score = nameTokens.length > 0 ? hits.length / nameTokens.length : 0;
  return { ...call, score, hits: hits.length };
});

const longestToken = nameTokens.sort((a, b) => b.length - a.length)[0] || '';

// Match threshold: 0.3 = at least 30% of account name tokens found in call title
const MATCH_THRESHOLD = 0.3;

const matched = scored
  .filter(c => 
    c.score >= MATCH_THRESHOLD 
    || (longestToken.length >= 3 && stripSuffixes(c.title || '').includes(longestToken))
  )
  .sort((a, b) => b.score - a.score || new Date(b.started || 0) - new Date(a.started || 0))
  .slice(0, 10);

return [{
  json: {
    callIds: matched.map(c => c.id),
    matchedCalls: matched.map(c => ({
      id: c.id, title: c.title, date: c.started, 
      url: c.url, score: c.score, hits: c.hits
    })),
    matchCount: matched.length,
    accountName,
    searchTokens: nameTokens,
    longestToken
  }
}];

// ===== SALESFORCE DATA =====
const sf = $('Salesforce - Get Opportunity').first().json;
const accountName = sf.Account?.Name || sf.Name || 'Unknown';

// ✏️ MAP YOUR SALESFORCE FIELDS HERE
// Standard fields work out of the box. Custom fields (ending in __c) must
// exist in your Salesforce org. Remove or rename fields as needed.
const sfData = {
  accountName: accountName,
  opportunityName: sf.Name || '',
  status: sf.StageName || '',
  closeDate: sf.CloseDate || '',
  amount: sf.Amount || '',
  seats: sf.Number_of_Seats__c || '',        // ✏️ Your seats/licenses field
  primaryUseCase: sf.Primary_Use_Case__c || '',  // ✏️ Your use case field
  useCaseNotes: sf.Use_Case_Notes__c || '',
  interactionChannels: sf.Interaction_Channels__c || '',
  currentCRM: sf.Current_CRM__c || '',
  currentTools: sf.Current_Tools__c || '',    // ✏️ Your tech stack field
  problemToSolve: sf.Problem_to_Solve__c || '',
  painPoints: sf.Pain_Points__c || '',
  metric1: sf.Metric_1__c || '',
  metric1Baseline: sf.Metric_1_Baseline__c || '',
  metric2: sf.Metric_2__c || '',
  metric2Baseline: sf.Metric_2_Baseline__c || '',
  metricNotes: sf.Metric_Notes__c || '',
  solutionDescription: sf.Solution_Description__c || '',
  decisionCriteria: sf.Decision_Criteria__c || '',
  executiveSponsor: sf.Executive_Sponsor__c || '',
  opportunityReviewLink: sf.Opportunity_Review_Link__c || '',
  leadId: sf.LeadId || '',
};

// ===== GONG DATA =====
const gongRaw = $input.first().json;
const calls = gongRaw.calls || [];
const matchedMeta = $('Match Gong Calls to Account').first().json.matchedCalls || [];

const callSummaries = calls.map(call => {
  const meta = matchedMeta.find(m => m.id === call.metaData?.id) || {};
  const content = call.content || {};
  return {
    title: call.metaData?.title || meta.title || 'Untitled',
    date: call.metaData?.started || meta.date || '',
    url: call.metaData?.url || meta.url || '',
    brief: content.brief || '',
    keyPoints: (content.keyPoints || []).map(kp => kp.text || kp).join('\n'),
    actionItems: (content.actionItems || []).map(ai => ai.text || ai).join('\n'),
    outline: (content.outline || []).map(o => {
      const section = o.section || '';
      const items = (o.items || []).map(i => i.text || i).join('; ');
      return section + ': ' + items;
    }).join('\n'),
  };
});

// Combine all Gong text + uploaded doc for keyword scanning
let allGongText = callSummaries.map(c => 
  [c.brief, c.keyPoints, c.actionItems, c.outline].join(' ')
).join(' ').toLowerCase();

// ===== UPLOADED PDF / CONVERSATION HISTORY =====
let pdfText = '';
try {
  const extracted = $('Extract PDF Text').first().json;
  pdfText = extracted.data || extracted.text || extracted.content || '';
  if (typeof pdfText !== 'string') pdfText = JSON.stringify(pdfText);
} catch(e) {
  pdfText = '';
}
if (pdfText && pdfText.trim().length > 0) {
  allGongText += ' ' + pdfText.toLowerCase();
}

// ===== INTAKE FORM CHECKLIST =====
// ✏️ CUSTOMIZE THIS to match your implementation team's intake requirements.
// Each item: label, SF field(s) to check, Gong keywords to scan for, required flag.
const intakeChecklist = [
  { section: 'Deal Overview', items: [
    { label: 'Status', sfFields: ['status'], gongKeywords: [], required: true },
    { label: 'Projected Close Date', sfFields: ['closeDate'], gongKeywords: [], required: true },
    { label: 'Deal Amount', sfFields: ['amount'], gongKeywords: ['pricing', 'cost', 'budget', 'contract'], required: true },
    { label: 'Seats / Licenses', sfFields: ['seats'], gongKeywords: ['seats', 'licenses', 'agents', 'users'], required: true },
  ]},
  { section: 'Use Case & Channels', items: [
    { label: 'Primary Use Case', sfFields: ['primaryUseCase'], gongKeywords: ['use case', 'workflow', 'scenario'], required: true },
    { label: 'Use Case Notes', sfFields: ['useCaseNotes'], gongKeywords: [], required: false },
    { label: 'Interaction Channels', sfFields: ['interactionChannels'], gongKeywords: ['channel', 'phone', 'chat', 'email', 'voice', 'digital'], required: true },
  ]},
  { section: 'Current Tech Stack', items: [
    { label: 'Current CRM', sfFields: ['currentCRM'], gongKeywords: ['salesforce', 'dynamics', 'hubspot', 'crm', 'zendesk'], required: true },
    { label: 'Current Tools', sfFields: ['currentTools'], gongKeywords: ['tool', 'platform', 'software', 'system'], required: true },
  ]},
  { section: 'Problem & Pain', items: [
    { label: 'Problem to Solve', sfFields: ['problemToSolve'], gongKeywords: ['problem', 'challenge', 'issue', 'struggle'], required: true },
    { label: 'Pain Points', sfFields: ['painPoints'], gongKeywords: ['pain', 'frustrat', 'difficult', 'inefficien'], required: true },
  ]},
  { section: 'Success Metrics', items: [
    { label: 'Metric 1', sfFields: ['metric1'], gongKeywords: ['metric', 'kpi', 'measure', 'goal', 'target'], required: true },
    { label: 'Metric 1 Baseline', sfFields: ['metric1Baseline'], gongKeywords: ['baseline', 'current', 'today'], required: true },
    { label: 'Metric 2', sfFields: ['metric2'], gongKeywords: [], required: false },
    { label: 'Metric 2 Baseline', sfFields: ['metric2Baseline'], gongKeywords: [], required: false },
    { label: 'Metric Notes', sfFields: ['metricNotes'], gongKeywords: [], required: false },
  ]},
  { section: 'Solution & Decision', items: [
    { label: 'Solution Description', sfFields: ['solutionDescription'], gongKeywords: ['solution', 'proposal', 'approach'], required: true },
    { label: 'Decision Criteria', sfFields: ['decisionCriteria'], gongKeywords: ['criteria', 'decision', 'evaluate', 'compare'], required: true },
  ]},
  { section: 'Stakeholders', items: [
    { label: 'Executive Sponsor', sfFields: ['executiveSponsor'], gongKeywords: ['sponsor', 'executive', 'vp', 'director', 'cto', 'cio', 'head of'], required: true },
  ]},
];

// Evaluate each checklist item
let totalItems = 0;
let completedItems = 0;
let intakeReport = '';

intakeChecklist.forEach(section => {
  intakeReport += `### ${section.section}\n`;
  section.items.forEach(item => {
    totalItems++;
    const hasSF = item.sfFields.some(f => !!sfData[f]);
    const hasGong = item.gongKeywords.length > 0 && item.gongKeywords.some(kw => allGongText.includes(kw));

    let status;
    if (hasSF) {
      status = 'COMPLETE (SF)';
      completedItems++;
    } else if (hasGong) {
      status = 'PARTIAL (mentioned in calls but not in Salesforce)';
      completedItems += 0.5;
    } else {
      status = item.required ? 'MISSING (required)' : 'MISSING (optional)';
    }

    const icon = hasSF ? '[OK]' : hasGong ? '[~]' : item.required ? '[X]' : '[-]';
    intakeReport += `${icon} ${item.label}: ${status}\n`;
  });
  intakeReport += '\n';
});

const readinessScore = Math.round((completedItems / totalItems) * 100);
const requiredMissing = [];
intakeChecklist.forEach(section => {
  section.items.forEach(item => {
    const hasSF = item.sfFields.some(f => !!sfData[f]);
    if (!hasSF && item.required) requiredMissing.push(item.label);
  });
});

// ===== BUILD LLM CONTEXT =====
let context = '# Salesforce Opportunity Data\n\n';
for (const [key, val] of Object.entries(sfData)) {
  if (val) context += `**${key}**: ${val}\n`;
}

context += '\n# Call Recording Summaries\n\n';
if (callSummaries.length === 0) {
  context += '_No matching calls found for this account._\n';
} else {
  callSummaries.forEach((c, i) => {
    context += `## Call ${i + 1}: ${c.title} (${c.date})\n`;
    context += `URL: ${c.url}\n`;
    if (c.brief) context += `**Brief:** ${c.brief}\n`;
    if (c.keyPoints) context += `**Key Points:**\n${c.keyPoints}\n`;
    if (c.actionItems) context += `**Action Items:**\n${c.actionItems}\n`;
    if (c.outline) context += `**Outline:**\n${c.outline}\n`;
    context += '\n';
  });
}

context += '\n# Intake Form Readiness Assessment\n\n';
context += `**Overall Readiness: ${readinessScore}%** (${Math.round(completedItems)} of ${totalItems} items have data)\n\n`;
context += `**Legend:** [OK] = In Salesforce | [~] = Mentioned in calls only | [X] = Missing (required) | [-] = Missing (optional)\n\n`;
context += intakeReport;

if (pdfText && pdfText.trim().length > 0) {
  context += '\n# Uploaded Document (Conversation History / Sales Notes)\n\n';
  context += pdfText.substring(0, 30000) + '\n\n';
}

if (requiredMissing.length > 0) {
  context += '### Required Items Still Missing\n';
  requiredMissing.forEach(item => context += `- **${item}**\n`);
  context += '\n';
}
context += '\n# Call References\n\n';
matchedMeta.forEach((c, i) => {
  context += `${i + 1}. **${c.title}** (${c.date})\n   ${c.url}\n`;
});
context += '\n';

// Truncate if too large for LLM context
if (context.length > 100000) {
  context = context.substring(0, 100000) + '\n\n[Context truncated due to length]';
}

// ===== PROMPTS =====
// ✏️ CUSTOMIZE the system prompt to match your company and role
const systemPrompt = `You are an Implementation Readiness Analyst. Your job is to synthesize CRM opportunity data, call recordings, and uploaded sales documents into a comprehensive pre-kickoff implementation brief.

You focus on:
- Understanding the customer's current tech stack and pain points
- Identifying the primary use case and success metrics
- Extracting key stakeholders and decision criteria
- Assessing whether all required intake form fields have been collected
- Highlighting risks, gaps, and items needing clarification before kickoff
- Providing actionable recommendations for the implementation team

Write in a professional, concise style. Use bullet points and clear section headers. Flag any contradictions between CRM data and call conversations.`;

const userPrompt = `Based on the following data, generate an Implementation Pre-Kickoff Brief for ${accountName}.

Structure the brief with these sections:

1. **Executive Summary** — 2-3 sentence overview of the deal and implementation scope
2. **Customer Profile** — Company, deal size, seats, close date, executive sponsor
3. **Current Tech Stack** — CRM, tools, and platforms currently in use
4. **Use Case & Pain Points** — Primary use case, interaction channels, core problems to solve
5. **Success Metrics** — Defined metrics with baselines, targets if available
6. **Solution Fit** — How the proposed solution maps to their needs, decision criteria alignment
7. **Key Insights from Sales Calls** — Synthesized themes, concerns, and commitments from call recordings. Include a reference list at the end with call titles, dates, and links.
8. **Intake Form Readiness** — Show the readiness score (${readinessScore}%). For each section, list what we HAVE and what is MISSING. For [~] items (found in calls but not CRM), note what was mentioned and recommend getting it formally documented. For [X] items (missing required), flag them as must-collect-before-kickoff.
9. **Data Gaps & Risks** — Missing information, contradictions, items to clarify at kickoff. Prioritize the ${requiredMissing.length} required missing fields.
10. **Recommended Kickoff Agenda Items** — Specific topics the implementation team should cover, with priority on filling intake form gaps

---

${context}`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    accountName,
    callCount: callSummaries.length,
    gapCount: requiredMissing.length,
    gaps: requiredMissing,
    readinessScore,
    totalItems,
    completedItems: Math.round(completedItems)
  }
}];

const input = $input.first().json;
const accountName = $('Prepare LLM Context').first().json.accountName || 'Customer';
const callCount = $('Prepare LLM Context').first().json.callCount || 0;
const gapCount = $('Prepare LLM Context').first().json.gapCount || 0;
const readinessScore = $('Prepare LLM Context').first().json.readinessScore || 0;

// Extract text from LLM response — handle multiple response formats
let briefText = input.message?.content 
  || input.text 
  || input.output 
  || input.content
  || (typeof input === 'string' ? input : JSON.stringify(input));

// Strip markdown code fences if present
briefText = briefText.replace(/^```html\n?/i, '').replace(/\n?```$/i, '');
briefText = briefText.replace(/^```markdown\n?/i, '').replace(/\n?```$/i, '');
briefText = briefText.replace(/^```\n?/, '').replace(/\n?```$/, '');

// Convert markdown to basic HTML for email
let html = briefText
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^# (.+)$/gm, '<h1>$1</h1>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>')
  .replace(/<\/ul>\s*<ul>/g, '')
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>');

html = `<div style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto; padding: 20px;">
  <div style="background: #1a1a2e; color: white; padding: 20px; border-radius: 8px 8px 0 0;">
    <h1 style="margin: 0; font-size: 22px;">Implementation Pre-Kickoff Brief</h1>
    <p style="margin: 5px 0 0; opacity: 0.8; font-size: 14px;">${accountName} | Generated ${new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</p>
  </div>
  <div style="background: #f0f4ff; padding: 12px 20px; border-left: 4px solid #3b82f6; margin: 16px 0;">
    <strong>Data Sources:</strong> Salesforce Opportunity + ${callCount} Call Recording${callCount !== 1 ? 's' : ''} | <strong>Intake Readiness:</strong> ${readinessScore}% | <strong>Required Gaps:</strong> ${gapCount}
  </div>
  <div style="padding: 0 0 20px;">
    <p>${html}</p>
  </div>
  <div style="border-top: 1px solid #e5e7eb; padding-top: 12px; font-size: 12px; color: #6b7280;">
    Auto-generated by Implementation Handoff Analyzer | ${new Date().toISOString()}
  </div>
</div>`;

return [{
  json: {
    html,
    plainText: briefText,
    subject: `Implementation Brief: ${accountName}`,
    accountName
  }
}];
